// // This module compares two 2-bit inputs A and B and outputs three signals:
// - A_eq: Low if A is equal to B
// - A_gt: Low if A is greater than B
// - A_lt: Low if A is less than B
module comparator_2bit(
    input [1:0] A,
    input [1:0] B,
    output A_eq,
    output A_gt,
    output A_lt
);
    assign A_eq = (A == B);
    assign A_gt = (A > B);
    assign A_lt = (A < B);
endmodule

